private void registerJavaDate(DateTimeFormatters dateTimeFormatters) {
	DateFormatterRegistrar dateFormatterRegistrar = new DateFormatterRegistrar();
	String datePattern = dateTimeFormatters.getDatePattern();
	if (datePattern != null) {
